(function($) {
    $.fn.trackCoords = function(options) {
        // Настройки по умолчанию
        var settings = $.extend({
            checkInterval: 30,
            sendInterval: 3000,
            url: '/save'
        }, options);

        // Для каждого элемента в выборке
        return this.each(function() {
            var $element = $(this);
            var mouseData = []; // Массив для хранения данных о позициях мыши
            var lastPosition = null; // Последняя зафиксированная позиция
            var timeInPosition = 0; // Время, проведенное в последней позиции
            
            // Функция для сбора данных о позиции мыши
            function trackMousePosition(e) {
                // Получаем координаты относительно элемента
                var offset = $element.offset();
                var relativeX = e.pageX - offset.left;
                var relativeY = e.pageY - offset.top;
                
                // Проверяем, находится ли курсор в пределах элемента
                if (relativeX >= 0 && relativeX <= $element.outerWidth() && 
                    relativeY >= 0 && relativeY <= $element.outerHeight()) {
                    
                    var currentPosition = {
                        x: relativeX,
                        y: relativeY
                    };
                    
                    // Если позиция изменилась
                    if (!lastPosition || 
                        lastPosition.x !== currentPosition.x || 
                        lastPosition.y !== currentPosition.y) {
                        
                        // Если была предыдущая позиция, сохраняем её с временем
                        if (lastPosition && timeInPosition > 0) {
                            mouseData.push({
                                x: lastPosition.x,
                                y: lastPosition.y,
                                time: timeInPosition
                            });
                        }
                        
                        // Устанавливаем новую позицию
                        lastPosition = currentPosition;
                        timeInPosition = settings.checkInterval; // Начинаем с текущего интервала
                    } else {
                        // Увеличиваем время в той же позиции
                        timeInPosition += settings.checkInterval;
                    }
                } else {
                    // Если курсор вышел за пределы элемента
                    if (lastPosition && timeInPosition > 0) {
                        mouseData.push({
                            x: lastPosition.x,
                            y: lastPosition.y,
                            time: timeInPosition
                        });
                        lastPosition = null;
                        timeInPosition = 0;
                    }
                }
            }
            
            // Функция для отправки данных на сервер
            function sendData() {
                if (mouseData.length > 0) {
                    // Добавляем последнюю позицию, если курсор все еще на элементе
                    if (lastPosition && timeInPosition > 0) {
                        mouseData.push({
                            x: lastPosition.x,
                            y: lastPosition.y,
                            time: timeInPosition
                        });
                        // Сбрасываем время для следующего периода
                        timeInPosition = 0;
                    }
                    
                    // Отправка данных на сервер
                    $.ajax({
                        url: settings.url,
                        type: 'POST',
                        data: JSON.stringify(mouseData),
                        contentType: 'application/json',
                        success: function() {
                            console.log('Данные успешно отправлены:', mouseData);
                        },
                        error: function(xhr, status, error) {
                            console.error('Ошибка при отправке данных:', error);
                        }
                    });
                    
                    // Очищаем массив данных
                    mouseData = [];
                }
            }
            
            // Запускаем отслеживание движения мыши
            $element.on('mousemove', trackMousePosition);
            
            // Запускаем периодическую отправку данных
            var sendInterval = setInterval(sendData, settings.sendInterval);
            
            // Сохраняем данные для возможности очистки
            $element.data('trackCoords', {
                sendInterval: sendInterval,
                mouseData: mouseData
            });
            
            // Очистка при удалении элемента
            $element.on('remove', function() {
                clearInterval(sendInterval);
                $element.off('mousemove', trackMousePosition);
            });
        });
    };
})(jQuery);


$(“div.container”).trackCoords({url: ‘/save.php’});